const envelope = $input.first().json ?? {};
const payload = envelope.body && typeof envelope.body === 'object' ? envelope.body : envelope;
const conversationContext = Array.isArray(payload.conversationContext)
  ? payload.conversationContext
      .filter((message) => message && typeof message === 'object')
      .map((message) => ({
        role: String(message.role ?? 'user'),
        content: String(message.content ?? '').trim(),
      }))
      .filter((message) => message.content.length > 0)
  : [];

return [{
  json: {
    chatPayload: {
      caseId: String(payload.caseId ?? `case_${Date.now()}`),
      question: String(payload.question ?? '').trim(),
      language: String(payload.language ?? 'vi').toLowerCase(),
      conversationContext,
    },
  },
}];

const item = $input.first().json;
const confidence = Number(item.confidence ?? 0);
return [{
  json: {
    success: true,
    chat: item,
    routeDecision: {
      queue: item.needsAttention || confidence < 0.55 ? 'manual_legal_follow_up_queue' : 'client_chat_queue',
      reason: item.needsAttention ? 'needs_attention' : confidence < 0.55 ? 'low_confidence' : 'normal_chat',
      autoEscalated: Boolean(item.needsAttention || confidence < 0.55),
    },
    timelineEvent: {
      caseId: item.caseId,
      eventType: 'AI_CHAT_COMPLETED',
      status: 'AIChatResponded',
      needsAttention: Boolean(item.needsAttention),
      source: 'n8n',
    },
    nextStep: item.needsAttention || confidence < 0.55 ? 'manual_legal_follow_up_queue' : 'client_chat_queue',
  },
}];
